# SCP: deny all actions in Regions outside eu-central-1 and eu-west-1
# Apply via aws organizations create-policy then attach to the target OU
# Policy document (save as region-lockdown.json):
{
  "Version": "2012-10-17",
  "Statement": [{
    "Sid": "DenyNonEURegions",
    "Effect": "Deny",
    "NotAction": [
      "iam:*", "organizations:*", "route53:*",
      "budgets:*", "waf:*", "cloudfront:*",
      "support:*", "sts:*", "health:*"
    ],
    "Resource": "*",
    "Condition": {
      "StringNotEquals": {
        "aws:RequestedRegion": ["eu-central-1", "eu-west-1"]
      }
    }
  }]
}

# Create a DynamoDB Global Table replicating between two Regions
# Step 1: Create the table in the primary Region
aws dynamodb create-table \n  --table-name UserSessions \n  --billing-mode PAY_PER_REQUEST \n  --attribute-definitions AttributeName=UserId,AttributeType=S \n  --key-schema AttributeName=UserId,KeyType=HASH \n  --region us-east-1

# Step 2: Add a replica in a second Region
aws dynamodb update-table \n  --table-name UserSessions \n  --replica-updates '[{
    "Create": {"RegionName": "eu-central-1"}
  }]' \n  --region us-east-1

# Writes to the table in either Region are replicated to the other
# with typically sub-second latency

# Create a latency-based routing record that serves from the nearest Region
# Primary record: us-east-1
aws route53 change-resource-record-sets \
  --hosted-zone-id Z1234567890 \
  --change-batch '{
    "Changes": [{
      "Action": "CREATE",
      "ResourceRecordSet": {
        "Name": "api.example.com",
        "Type": "A",
        "SetIdentifier": "us-east-1",
        "Region": "us-east-1",
        "AliasTarget": {
          "HostedZoneId": "Z35SXDOTRQ7X7K",
          "DNSName": "my-alb-us.us-east-1.elb.amazonaws.com.",
          "EvaluateTargetHealth": true
        }
      }
    }]
  }'

# Add health check: if us-east-1 ALB is unhealthy, Route 53 stops sending traffic there
aws route53 create-health-check \
  --caller-reference my-app-us-east-1-hc \
  --health-check-config '{
    "Type": "HTTPS",
    "FullyQualifiedDomainName": "my-alb-us.us-east-1.elb.amazonaws.com",
    "Port": 443,
    "ResourcePath": "/health",
    "RequestInterval": 30,
    "FailureThreshold": 3
  }'
